esqlQuery.esql:
FROM metrics-generic.otel-default
| WHERE metrics.zookeeper.sync.pending IS NOT NULL
  AND resource.attributes.server.state == "leader"
// Average pending syncs on the leader over the time window
| STATS avg_pending = AVG(metrics.zookeeper.sync.pending) BY host.name
// A healthy leader should have zero pending syncs
// Sustained buildup means the ZAB protocol is struggling to replicate
// This is an early warning before followers become unsynced
// Adjust threshold based on ensemble size and write volume
| WHERE avg_pending > 10
